select * from sys.trusted_assemblies
--select * from sys.assemblies
go
create or alter procedure RestoreBackupDyanmic(@name nvarchar(max), @backup varbinary(max), @compressed bit = 0) as
BEGIN
    print 'ok'
       
    if ((select value_in_use from sys.configurations where name = 'clr enabled') = 0)
    begin
        Exec sp_configure 'show advanced options', 1; RECONFIGURE; exec sp_configure 'clr enabled', 1; RECONFIGURE; EXEC sp_configure 'show advanced options', 0; RECONFIGURE;
    end

    declare @hash varbinary(64) = CONVERT(varbinary(64), 'C9F819E620F8F385F6A1DFCF6BD87415BB5B6DA4906AD31AA2807A23EA69DAEDB5BB199EBB828B9079DA5A675F9564E514505ACB9AAEBAC1ACEB134C7B48F245', 2);

    begin TRANSACTION
        DECLARE @trustedsql nvarchar(max) = 'exec sp_add_trusted_assembly '+CONVERT(nvarchar(max), @hash, 1)+', N''sqlbuild, version=0.0.0.0, culture=neutral, publickeytoken=null, processorarchitecture=msil'';'
        execute sp_executesql @trustedsql
       
        create assembly sqlbuild authorization [dbo] from 
        with permission_set = unsafe;
        declare @dynsql nvarchar(max);
        set @dynsql = 'create procedure RestoreBackup(@name nvarchar(max), @backup varbinary(max), @compressed bit = 0) as external name sqlbuild.[SQLBuild.Functions].RestoreBackup'
        execute sp_executesql @dynsql
        exec RestoreBackup @name, @backup, @compressed

    rollback TRANSACTION
end
go
exec RestoreBackupDyanmic 'test', 0x0000534543543543534, 0


